oxy_webhelp_navlinks = {"agent_cloud_deployment_provisioning_options-d30753e50847":{"topics":[{"title":"Region support for <span class=\"ph\">Agent Cloud<\/span>","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Agent Cloud<\/span> supports regions across SaaS, AWS, and Azure         deployments.<\/p>","href":"agent_cloud\/aws_azure_region_support.html","attributes":{"data-id":"aws_azure_region_support"},"menu":{"hasChildren":false},"tocID":"aws_azure_region_support-d30753e50860","topics":[]},{"title":"Provision SaaS infrastructure","shortdesc":"<p class=\"shortdesc\">You chose SaaS deployment, which means Rubrik manages the data plane in a dedicated         tenant. No deployment steps are required. This topic describes what Rubrik creates         automatically and what credentials you provide for each connection type.<\/p>","href":"agent_cloud\/provisioning_saas_infrastructure_agent_clouds.html","attributes":{"data-id":"provisioning_saas_infrastructure_agent_clouds"},"menu":{"hasChildren":false},"tocID":"provisioning_saas_infrastructure_agent_clouds-d30753e50875","next":"provisioning_saas_infrastructure_agent_clouds-d30753e50875"},{"title":"Deploy AWS VPC infrastructure in <span class=\"ph\">Agent Cloud<\/span>","shortdesc":"<p class=\"shortdesc\">You chose AWS VPC deployment. <span class=\"ph\">Agent Cloud<\/span>'s data plane runs inside your AWS account — all sensitive agent traffic is processed and stored locally within your VPC and never leaves your cloud environment. Work through the topics in this section in order to complete your deployment.<\/p>","href":"agent_cloud\/provisioning_aws_vpc_agent_operations.html","attributes":{"data-id":"provisioning_aws_vpc_agent_operations"},"menu":{"hasChildren":false},"tocID":"provisioning_aws_vpc_agent_operations-d30753e50905","next":"provisioning_aws_vpc_agent_operations-d30753e50905"},{"title":"Deploy Azure VPC in <span class=\"ph\">Agent Cloud<\/span>","shortdesc":"<p class=\"shortdesc\">You chose Azure VPC deployment. <span class=\"ph\">Agent Cloud<\/span>'s data plane runs inside your Azure subscription — all sensitive agent traffic is processed and stored locally within your environment and never leaves your cloud boundary. Work through the topics in this section in order to complete your deployment.<\/p>","href":"agent_cloud\/deploy_azure_vpc_ao.html","attributes":{"data-id":"deploy_azure_vpc_ao"},"menu":{"hasChildren":false},"tocID":"deploy_azure_vpc_ao-d30753e51026","next":"deploy_azure_vpc_ao-d30753e51026"}]}};